if (enableComposeMetrics && name in publicModules) {
    val outputDir = layout.buildDirectory.dir("composeMetrics").get().asFile
    metricsDestination = outputDir
    reportsDestination = outputDir
}

if (requested.group == "org.jetbrains.kotlinx" && requested.name == "atomicfu") {
    useVersion(libs.versions.atomicfu.get())
}

if (currentEntries is Iterable<*>) {
    currentEntries.filterNotNullTo(existingEntries)
} else {
    return
}

when (current) {
    is AsyncImagePainter.State.Success -> current.result
    is AsyncImagePainter.State.Error -> current.result
    else -> return null
}

if (field != value) {
    field = value
    restart()
    if (value != null) {
        inputFlow.value = value
    }
}

if (previous.painter !== current.painter) {
    (previous.painter as? RememberObserver)?.onForgotten()
    (current.painter as? RememberObserver)?.onRemembered()
}

if (!constraints.isZero) {
    val c = continuations
    if (c.isNotEmpty()) {
        continuations = mutableListOf()
        c.forEach { it.resume(Unit) }
    }
}

if (preferEndFirstIntrinsicSize) {
    if (isEndSpecified) return endSize
    if (isStartSpecified) return startSize
}

if (isStartSpecified && isEndSpecified) {
    return Size(
        width = maxOf(startSize.width, endSize.width),
        height = maxOf(startSize.height, endSize.height),
    )
}

if (preferExactIntrinsicSize) {
    if (isStartSpecified) return startSize
    if (isEndSpecified) return endSize
}

when {
    isUnspecified -> CoilSize.ORIGINAL
    isPositive -> CoilSize(width.toDimension(), height.toDimension())
    else -> null
}

when (val result = imageLoader.execute(request)) {
    is SuccessResult -> Success(result.image.asPainter(request.context), result)
    is ErrorResult -> Error(result.image?.asPainter(request.context), result)
}

when (this) {
    is BitmapImage -> BitmapPainter(
        image = toBitmap().asComposeImageBitmap(),
        filterQuality = filterQuality,
    )
    else -> ImagePainter(this)
}

if (strategy.supports(mimeType, source)) {
    val exifInterface = ExifInterface(ExifInterfaceInputStream(source.peek().inputStream()))
    return ExifData(exifInterface.isFlipped, exifInterface.rotationDegrees)
} else {
    return ExifData.NONE
}

if (exifData.isRotated) {
    matrix.postRotate(exifData.rotationDegrees.toFloat(), centerX, centerY)
}

if (exifData.isSwapped) {
    createBitmap(inBitmap.height, inBitmap.width, inBitmap.safeConfig)
} else {
    createBitmap(inBitmap.width, inBitmap.height, inBitmap.safeConfig)
}

if (options.bitmapConfig.isHardware) {
    ImageDecoder.ALLOCATOR_HARDWARE
} else {
    ImageDecoder.ALLOCATOR_SOFTWARE
}

if (options.allowRgb565) {
    ImageDecoder.MEMORY_POLICY_LOW_RAM
} else {
    ImageDecoder.MEMORY_POLICY_DEFAULT
}

if (fileSystem === FileSystem.SYSTEM) {
    val file = fileOrNull()
    if (file != null) {
        return ImageDecoder.createSource(file.toFile())
    }
}

if (this is BitmapImage &&
        bitmap.width == width &&
        bitmap.height == height &&
        bitmap.config == config
    ) {
        return bitmap
    }

if (this is BitmapDrawable) {
    bitmap.asImage(shareable)
} else {
    DrawableImage(this, shareable)
}

when (this) {
    is DrawableImage -> drawable
    is BitmapImage -> bitmap.toDrawable(resources)
    else -> ImageDrawable(this)
}

if (data.scheme == SCHEME_ANDROID_RESOURCE) {
    // 'android.resource' uris can change if night mode is enabled/disabled.
    return "$data:${options.context.resources.configuration.nightMode}"
}

try {
    context.resources.getResourceEntryName(data) != null
} catch (_: Resources.NotFoundException) {
    false
}

if (options.enableStaticImageDecoder()) {
    add(
        StaticImageDecoder.Factory(
            parallelismLock = parallelismLock,
        ),
    )
}

if (durationMillis > 0) {
    CrossfadeTransition.Factory(durationMillis)
} else {
    Transition.Factory.NONE
}

if (sizeResolver == null) {
    sizeResolver = request.resolveSizeResolver()
    builder.size(sizeResolver)
}

if (defined.sizeResolver == null && sizeResolver == SizeResolver.ORIGINAL) {
    return Precision.INEXACT
}

if (target is ViewTarget<*> &&
            sizeResolver is ViewSizeResolver<*> &&
            target.view is ImageView &&
            target.view === sizeResolver.view
        ) {
            return Precision.INEXACT
        }

if (bitmapConfig != this.bitmapConfig) {
    builder = builder.set(Extras.Key.bitmapConfig, bitmapConfig)
}
